import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.preference.PreferenceManager
import androidx.fragment.app.FragmentActivity

class FingerprintAuthentication {

    private fun createBiometricPrompt(activity: FragmentActivity): BiometricPrompt {
        val executor = ContextCompat.getMainExecutor(activity)

        val biometricPrompt = BiometricPrompt(
            activity,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)

                    // Set authenticated flag in SharedPreferences
                    val sharedPreferences = PreferenceManager.getDefaultSharedPreferences(activity)
                    sharedPreferences.edit().putBoolean("authenticated", true).apply()

                    // Navigate to home screen or perform desired action
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)

                    // Handle error cases, such as canceling authentication or biometric not available
                }
            }
        )

        return biometricPrompt
    }

    fun authenticate(activity: FragmentActivity) {
        val biometricPrompt = createBiometricPrompt(activity)

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint Authentication")
            .setSubtitle("Please scan your fingerprint to authenticate")
            .setNegativeButtonText("Cancel")
            .build()

        biometricPrompt.authenticate(promptInfo)
    }
}